const nacl = require\('tweetnacl'\);
const { encodeBase64, decodeBase64, decodeUTF8, encodeUTF8 } = require\('tweetnacl-util'\);
const axios = require\('axios'\);
const API = 'http://localhost:3000/api/v1';

async function test\(\) {
  console.log\('=== SIMULATING EXACT BROWSER FLOW ===\\n'\);

  // === ALICE TAB ===
  console.log\('--- ALICE TAB ---'\);

  // 1. Login
  const r1 = await axios.post\(API + '/auth/login', { user: { email: 'alice@test.com', password: 'password123' } }\);
  const aliceToken = r1.data.token;
  const aliceUser = r1.data.user;
  console.log\('1. Login OK, user:', aliceUser.display_name, aliceUser.id\);

  // 2. getOrCreateKeyPair \(generates new keys, stores in sessionStorage\)
  const aliceKeys = nacl.box.keyPair\(\);
  const alicePK = encodeBase64\(aliceKeys.publicKey\);
  const aliceSK = encodeBase64\(aliceKeys.secretKey\);
  console.log\('2. Generated keypair'\);

  // 3. updateMyKeys  
  await axios.put\(API + '/users/keys', { public_key: alicePK }, { headers: { Authorization: 'Bearer ' + aliceToken } }\);
  console.log\('3. Uploaded public key'\);

  // === BOB TAB \(separate sessionStorage\) ===
  console.log\('\\n--- BOB TAB ---'\);

  const r2 = await axios.post\(API + '/auth/login', { user: { email: 'bob@test.com', password: 'password123' } }\);
  const bobToken = r2.data.token;
  const bobUser = r2.data.user;
  console.log\('1. Login OK, user:', bobUser.display_name, bobUser.id\);

  const bobKeys = nacl.box.keyPair\(\);
  const bobPK = encodeBase64\(bobKeys.publicKey\);
  const bobSK = encodeBase64\(bobKeys.secretKey\);
  console.log\('2. Generated keypair'\);

  await axios.put\(API + '/users/keys', { public_key: bobPK }, { headers: { Authorization: 'Bearer ' + bobToken } }\);
  console.log\('3. Uploaded public key'\);

  // === ALICE CREATES CHAT ===
  console.log\('\\n--- ALICE CREATES CHAT ---'\);

  const convRes = await axios.post\(API + '/conversations', 
    { participant_ids: [bobUser.id] }, 
    { headers: { Authorization: 'Bearer ' + aliceToken } }
  \);
  const conv = convRes.data.conversation;
  console.log\('Created conversation:', conv.id\);

  // === ALICE OPENS CHATSCREEN \(init\) ===
  console.log\('\\n--- ALICE CHATSCREEN INIT ---'\);

  // getOrCreateKeyPair returns existing \(from sessionStorage\)
  // secretKeyRef.current = aliceSK
  console.log\('secretKey loaded:', !!aliceSK\);

  // Load other participant's key
  const otherP = conv.participants.find\(p => p.id !== aliceUser.id\);
  console.log\('Other participant:', otherP.display_name, otherP.id\);

  const otherKeyRes = await axios.get\(API + '/users/' + otherP.id + '/keys', { headers: { Authorization: 'Bearer ' + aliceToken } }\);
  const otherPubKey = otherKeyRes.data.public_key;
  console.log\('Other pub key loaded:', !!otherPubKey, 'matches bob:', otherPubKey === bobPK\);

  // === ALICE SENDS MESSAGE \(handleSend\) ===
  console.log\('\\n--- ALICE SENDS MESSAGE ---'\);

  const plaintext = 'Hello Bob!';

  // encryptDirectMessage
  const msgBytes = decodeUTF8\(plaintext\);
  const nonce = nacl.randomBytes\(nacl.box.nonceLength\);
  const encrypted = nacl.box\(msgBytes, nonce, decodeBase64\(otherPubKey\), decodeBase64\(aliceSK\)\);
  const encBody = encodeBase64\(encrypted\);
  const encNonce = encodeBase64\(nonce\);
  console.log\('Encrypted:', encBody.substring\(0, 30\) + '...'\);

  // api.sendMessage
  const sendRes = await axios.post\(
    API + '/conversations/' + conv.id + '/messages',
    { message: { encrypted_body: encBody, nonce: encNonce, message_type: 'text' } },
    { headers: { Authorization: 'Bearer ' + aliceToken } }
  \);
  console.log\('Sent! Status:', sendRes.status, 'Message ID:', sendRes.data.message.id\);

  // fetchAndDecryptMessages \(called after send\)
  const msgsRes = await axios.get\(API + '/conversations/' + conv.id + '/messages', { headers: { Authorization: 'Bearer ' + aliceToken } }\);
  const rawMsgs = msgsRes.data.messages;
  console.log\('Fetched', rawMsgs.length, 'messages'\);

  // Decrypt \(using otherPubKey = bob's key\)
  for \(const msg of rawMsgs\) {
    const dec = nacl.box.open\(decodeBase64\(msg.encrypted_body\), decodeBase64\(msg.nonce\), decodeBase64\(otherPubKey\), decodeBase64\(aliceSK\)\);
    console.log\('  Decrypted:', encodeUTF8\(dec\)\);
  }

  // === BOB OPENS CHATSCREEN ===
  console.log\('\\n--- BOB SEES MESSAGE ---'\);

  // Bob's list of conversations
  const bobConvs = await axios.get\(API + '/conversations', { headers: { Authorization: 'Bearer ' + bobToken } }\);
  console.log\('Bob has', bobConvs.data.conversations.length, 'conversations'\);

  const bobConv = bobConvs.data.conversations[0];
  console.log\('Bob opens:', bobConv.display_title\);

  // Bob fetches messages
  const bobMsgs = await axios.get\(API + '/conversations/' + bobConv.id + '/messages', { headers: { Authorization: 'Bearer ' + bobToken } }\);
  console.log\('Bob fetched', bobMsgs.data.messages.length, 'messages'\);

  // Bob loads Alice's key
  const bobOtherP = bobConv.participants.find\(p => p.id !== bobUser.id\);
  const aliceKeyRes = await axios.get\(API + '/users/' + bobOtherP.id + '/keys', { headers: { Authorization: 'Bearer ' + bobToken } }\);
  const alicePubKeyFetched = aliceKeyRes.data.public_key;
  console.log\('Bob fetched Alice key, matches:', alicePubKeyFetched === alicePK\);

  // Bob decrypts
  for \(const msg of bobMsgs.data.messages\) {
    const dec = nacl.box.open\(decodeBase64\(msg.encrypted_body\), decodeBase64\(msg.nonce\), decodeBase64\(alicePubKeyFetched\), decodeBase64\(bobSK\)\);
    console.log\('  Bob decrypted:', encodeUTF8\(dec\)\);
  }

  // === BOB REPLIES ===
  console.log\('\\n--- BOB REPLIES ---'\);
  const reply = 'Hey Alice!';
  const replyBytes = decodeUTF8\(reply\);
  const replyNonce = nacl.randomBytes\(nacl.box.nonceLength\);
  const replyEnc = nacl.box\(replyBytes, replyNonce, decodeBase64\(alicePubKeyFetched\), decodeBase64\(bobSK\)\);

  await axios.post\(
    API + '/conversations/' + bobConv.id + '/messages',
    { message: { encrypted_body: encodeBase64\(replyEnc\), nonce: encodeBase64\(replyNonce\), message_type: 'text' } },
    { headers: { Authorization: 'Bearer ' + bobToken } }
  \);
  console.log\('Bob sent reply'\);

  // Alice polls \(fetchAndDecryptMessages via 3s interval\)
  const alicePoll = await axios.get\(API + '/conversations/' + conv.id + '/messages', { headers: { Authorization: 'Bearer ' + aliceToken } }\);
  console.log\('Alice poll:', alicePoll.data.messages.length, 'messages'\);
  for \(const msg of alicePoll.data.messages\) {
    const dec = nacl.box.open\(decodeBase64\(msg.encrypted_body\), decodeBase64\(msg.nonce\), decodeBase64\(otherPubKey\), decodeBase64\(aliceSK\)\);
    console.log\('  Alice sees:', encodeUTF8\(dec\)\);
  }

  console.log\('\\n=== EVERYTHING WORKS ==='\);
}
test\(\).catch\(e => { console.error\('FAILED:', e.response?.data || e.message\); process.exit\(1\); }\);
